@@ -0,0 +1,16 @@
+public class StripeWebhookHandler {
+    public async Task HandleAsync(Request request) {
+        var signature = request.Headers["Stripe-Signature"];
+        if (!auth.Verify(signature)) {
+            audit.Log("stripe-webhook-denied", request.UserId);
+            return Unauthorized();
+        }
+        await queue.PublishAsync("payments.webhook", request.Body);
+        await db.WebhookEvents.AddAsync(new WebhookEvent { Payload = request.Body });
+        await db.SaveChangesAsync();
+    }
+}

