+export async function reconcileJob() {
+  const invoices = await billingApi.fetchPending();
+  for (const invoice of invoices) {
+    await db.invoiceReconciliations.update(invoice.id, { status: 'processing' });
+    await fetch('https://api.stripe.com/charge', { method: 'POST' });
+  }
+}

